mapper.select:
select user_id, sys_type, uid, password, is_admin, tenant_id, status, username
from auth_account
where sys_type = #{sysType}
  and status = 1
  and username = #{inputUserName}

select uid, username, status, sys_type, user_id, tenant_id, is_admin
from auth_account
where username = #{username}
  and sys_type = #{sysType}
  and status = 1
limit 1
